// Collect mapped events from every feed, then: (a) keep near-term one-off
// events (raw ICS feeds dump full history) but ALWAYS pass recurring masters
// through — Prefrontal expands them into concrete occurrences, so a weekly
// event whose master is dated months ago still surfaces today; (b) guarantee a
// title, since ICS events without SUMMARY would 422 the whole batch; (c) DEDUPE
// across feeds — the same event often appears on more than one calendar
// (personal mirrors work/Outlook invites). The dedupe key keeps a series master
// and its modified occurrences distinct while still collapsing the same item
// mirrored on two feeds. First feed wins (order: personal, work, outlook, family);
// the dropped namespace's stale row is pruned on the next sync.
const now = Date.now();
const FROM = now - 60 * 60 * 1000;
const TO = now + 36 * 60 * 60 * 1000;
const seen = new Set();
const events = [];
for (const item of $input.all()) {
  const e = item.json;
  const recurring = !!e.rrule;
  if (recurring) {
    // Drop series that already ended, so dead masters don't pile up in the batch.
    const m = /UNTIL=(\d{4})(\d{2})(\d{2})/.exec(e.rrule);
    if (m) { const until = Date.parse(`${m[1]}-${m[2]}-${m[3]}T23:59:59Z`); if (until < FROM) continue; }
  } else {
    // One-off (or an already-concrete modified occurrence): window-filter it.
    const t = Date.parse(e.start_at);
    if (Number.isNaN(t) || t < FROM || t > TO) continue;
  }
  const uid = String(e.external_id || '').replace(/^[^:]+:/, '');
  const key = uid ? uid + '|' + (e.recurrence_id || (recurring ? 'MASTER' : '')) : '';
  if (key) { if (seen.has(key)) continue; seen.add(key); }
  events.push({ ...e, title: (e.title && String(e.title).trim()) || '(busy)' });
}
return [{ json: { events } }];

